    /**
     * Validate that a URI belongs to an allowed origin.
     */
    private boolean isAllowedOrigin(Uri uri) {
        if (uri == null) return false;
        String origin = uri.getScheme() + "://" + uri.getHost();
        // Handle non-standard ports if needed
        if (uri.getPort() != -1 && uri.getPort() != 443) {
            origin += ":" + uri.getPort();
        }
        return ALLOWED_ORIGINS.contains(origin);
    }

    /**
     * Validate that the current WebView URL is from an allowed origin before processing bridge calls.
     */
    private boolean isCurrentOriginTrusted() {
        String currentUrl = webView.getUrl();
        if (currentUrl == null) return false;
        try {
            Uri uri = Uri.parse(currentUrl);
            return isAllowedOrigin(uri);
        } catch (Exception e) {
            Log.e(TAG, "Failed to parse current URL", e);
            return false;
        }
    }

    /**
     * Rate limiting check for bridge methods.
     */
    private boolean isRateLimited(String methodName) {
        long now = System.currentTimeMillis();
        long[] timestamps = rateLimitMap.computeIfAbsent(methodName,
                k -> new long[MAX_CALLS_PER_WINDOW]);

        synchronized (timestamps) {
            // Find the oldest timestamp in the window
            int count = 0;
            for (long ts : timestamps) {
                if (now - ts < RATE_LIMIT_WINDOW_MS) {
                    count++;
                }
            }
            if (count >= MAX_CALLS_PER_WINDOW) {
                Log.w(TAG, "Rate limit exceeded for bridge method: " + methodName);
                return true;
            }
            // Record this call
            long oldest = Long.MAX_VALUE;
            int oldestIdx = 0;
            for (int i = 0; i < timestamps.length; i++) {
                if (timestamps[i] < oldest) {
                    oldest = timestamps[i];
                    oldestIdx = i;
                }
            }
            timestamps[oldestIdx] = now;
            return false;
        }
    }

    /**
     * Validate and parse a JSON message from the web bridge.
     * Expected format: {"action": "...", "nonce": "uuid", "params": {...}}
     */
    private JSONObject validateBridgeMessage(String jsonMessage) {
        if (jsonMessage == null || jsonMessage.isEmpty()) {
            Log.w(TAG, "Empty bridge message received");
            return null;
        }

        // Limit message size to prevent abuse
        if (jsonMessage.length() > 4096) {
            Log.w(TAG, "Bridge message too large: " + jsonMessage.length() + " bytes");
            return null;
        }

        try {
            JSONObject msg = new JSONObject(jsonMessage);

            // Validate required fields
            if (!msg.has("action") || !msg.has("nonce")) {
                Log.w(TAG, "Bridge message missing required fields");
                return null;
            }

            // Replay protection via nonce
            String nonce = msg.getString("nonce");
            if (nonce.length() > 64 || !nonce.matches("[a-zA-Z0-9\\-]+")) {
                Log.w(TAG, "Invalid nonce format");
                return null;
            }
            if (usedNonces.contains(nonce)) {
                Log.w(TAG, "Replay detected - nonce already used: " + nonce);
                return null;
            }
            usedNonces.add(nonce);

            // Periodically clean old nonces to prevent memory growth
            if (usedNonces.size() > 10000) {
                usedNonces.clear();
            }

            return msg;
        } catch (JSONException e) {
            Log.w(TAG, "Invalid JSON in bridge message", e);
            return null;
        }
    }

    /**
     * Inject a minimal bridge protocol helper into the page.
     * This provides the web app with a structured way to call native methods.
     */
    private void injectBridgeProtocol(WebView view) {
        String script = "(function() {" +
                "  if (window._nativeBridgeReady) return;" +
                "  window._nativeBridgeReady = true;" +
                "  window.callNative = function(action, params) {" +
                "    var msg = JSON.stringify({" +
                "      action: action," +
                "      nonce: crypto.randomUUID ? crypto.randomUUID() : " +
                "             (Date.now().toString(36) + Math.random().toString(36).substr(2))," +
                "      params: params || {}" +
                "    });" +
                "    return NativeBridge.handleMessage(msg);" +
                "  };" +
                "  window.dispatchEvent(new Event('nativeBridgeReady'));" +
                "})();";
        view.evaluateJavascript(script, null);
    }

    /**
     * Send a callback/event to the web layer.
     */
    private void sendToWeb(String eventName, JSONObject data) {
        mainHandler.post(() -> {
            String script = String.format(
                    "(function() { window.dispatchEvent(new CustomEvent('%s', { detail: %s })); })();",
                    sanitizeEventName(eventName),
                    data != null ? data.toString() : "{}"
            );
            webView.evaluateJavascript(script, null);
        });
    }

    /**
     * Sanitize event name to prevent injection.
     */
    private String sanitizeEventName(String name) {
        if (name == null) return "unknown";
        return name.replaceAll("[^a-zA-Z0-9_]", "");
    }

    /**
     * The JavaScript bridge interface - MINIMAL surface area.
     * Only one entry point that routes to specific handlers after validation.
     */
    public class SecureNativeBridge {

        /**
         * Single entry point for all web-to-native communication.
         * All messages are validated, origin-checked, and rate-limited.
         */
        @JavascriptInterface
        public String handleMessage(String jsonMessage) {
            // SECURITY: Verify the calling origin
            if (!isCurrentOriginTrusted()) {
                Log.e(TAG, "Bridge call from untrusted origin rejected");
                return createErrorResponse("UNAUTHORIZED", "Origin not trusted");
            }

            // SECURITY: Rate limiting
            if (isRateLimited("handleMessage")) {
                return createErrorResponse("RATE_LIMITED", "Too many requests");
            }

            // SECURITY: Validate and parse the message
            JSONObject msg = validateBridgeMessage(jsonMessage);
            if (msg == null) {
                return createErrorResponse("INVALID_MESSAGE", "Message validation failed");
            }

            try {
                String action = msg.getString("action");
                JSONObject params = msg.optJSONObject("params");
                if (params == null) params = new JSONObject();

                // Route to specific handlers based on action
                switch (action) {
                    case "getDeviceInfo":
                        return handleGetDeviceInfo();
                    case "requestCameraPermission":
                        return handleRequestCameraPermission();
                    case "requestLocation":
                        return handleRequestLocation();
                    case "initiatePayment":
                        return handleInitiatePayment(params);
                    case "hapticFeedback":
                        return handleHapticFeedback();
                    case "getAppVersion":
                        return handleGetAppVersion();
                    default:
                        Log.w(TAG, "Unknown bridge action: " + action);
                        return createErrorResponse("UNKNOWN_ACTION",
                                "Action not recognized: " + action);
                }
            } catch (JSONException e) {
                Log.e(TAG, "Error processing bridge message", e);
                return createErrorResponse("PROCESSING_ERROR", "Failed to process message");
            }
        }
    }

