    /**
     * Request camera permission - returns current status and triggers permission request if needed.
     */
    private String handleRequestCameraPermission() {
        try {
            JSONObject response = new JSONObject();
            boolean hasPermission = ContextCompat.checkSelfPermission(this,
                    Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED;

            if (hasPermission) {
                response.put("status", "success");
                JSONObject data = new JSONObject();
                data.put("granted", true);
                response.put("data", data);
            } else {
                // Request permission on the main thread
                mainHandler.post(() -> ActivityCompat.requestPermissions(
                        SecureHybridWebViewActivity.this,
                        new String[]{Manifest.permission.CAMERA},
                        PERMISSION_REQUEST_CAMERA
                ));
                response.put("status", "pending");
                JSONObject data = new JSONObject();
                data.put("message", "Permission dialog shown. Listen for 'cameraPermissionResult' event.");
                response.put("data", data);
            }
            return response.toString();
        } catch (JSONException e) {
            return createErrorResponse("ERROR", "Failed to check camera permission");
        }
    }

    /**
     * Request device location with proper permission checks.
     */
    @SuppressLint("MissingPermission")
    private String handleRequestLocation() {
        try {
            JSONObject response = new JSONObject();

            boolean hasFineLocation = ContextCompat.checkSelfPermission(this,
                    Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED;
            boolean hasCoarseLocation = ContextCompat.checkSelfPermission(this,
                    Manifest.permission.ACCESS_COARSE_LOCATION) == PackageManager.PERMISSION_GRANTED;

            if (!hasFineLocation && !hasCoarseLocation) {
                // Request permission
                mainHandler.post(() -> ActivityCompat.requestPermissions(
                        SecureHybridWebViewActivity.this,
                        new String[]{
                                Manifest.permission.ACCESS_FINE_LOCATION,
                                Manifest.permission.ACCESS_COARSE_LOCATION
                        },
                        PERMISSION_REQUEST_LOCATION
                ));
                response.put("status", "pending");
                JSONObject data = new JSONObject();
                data.put("message", "Permission dialog shown. Listen for 'locationResult' event.");
                response.put("data", data);
                return response.toString();
            }

            // Permission granted - get last known location
            LocationManager locationManager = (LocationManager) getSystemService(LOCATION_SERVICE);
            if (locationManager == null) {
                return createErrorResponse("UNAVAILABLE", "Location service unavailable");
            }

            Location location = null;
            if (hasFineLocation) {
                location = locationManager.getLastKnownLocation(LocationManager.GPS_PROVIDER);
            }
            if (location == null && hasCoarseLocation) {
                location = locationManager.getLastKnownLocation(LocationManager.NETWORK_PROVIDER);
            }

            if (location != null) {
                response.put("status", "success");
                JSONObject data = new JSONObject();
                // Round coordinates to reduce precision for privacy
                data.put("latitude", Math.round(location.getLatitude() * 10000.0) / 10000.0);
                data.put("longitude", Math.round(location.getLongitude() * 10000.0) / 10000.0);
                data.put("accuracy", location.getAccuracy());
                data.put("timestamp", location.getTime());
                response.put("data", data);
            } else {
                response.put("status", "success");
                JSONObject data = new JSONObject();
                data.put("message", "Location not available yet. Listen for 'locationResult' event.");
                response.put("data", data);
            }
            return response.toString();
        } catch (JSONException e) {
            return createErrorResponse("ERROR", "Failed to get location");
        }
    }

    /**
     * Initiate a payment flow with strict parameter validation.
     */
    private String handleInitiatePayment(JSONObject params) {
        try {
            // Validate required payment parameters
            if (!params.has("amount") || !params.has("currency") || !params.has("orderId")) {
                return createErrorResponse("INVALID_PARAMS",
                        "Payment requires amount, currency, and orderId");
            }

            double amount = params.getDouble("amount");
            String currency = params.getString("currency");
            String orderId = params.getString("orderId");

            // Validate amount
            if (amount <= 0 || amount > 999999.99) {
                return createErrorResponse("INVALID_PARAMS", "Invalid payment amount");
            }

            // Validate currency (ISO 4217 - 3 letter code)
            if (!currency.matches("^[A-Z]{3}$")) {
                return createErrorResponse("INVALID_PARAMS", "Invalid currency code");
            }

            // Validate orderId format (alphanumeric with hyphens, reasonable length)
            if (!orderId.matches("^[a-zA-Z0-9\\-]{1,64}$")) {
                return createErrorResponse("INVALID_PARAMS", "Invalid order ID format");
            }

            // Generate a payment session token
            String paymentSessionId = UUID.randomUUID().toString();

            Log.i(TAG, "Payment initiated - Order: " + orderId
                    + ", Amount: " + amount + " " + currency
                    + ", Session: " + paymentSessionId);

            // In a real implementation, this would launch a native payment UI
            // (Google Pay, in-app billing, etc.) and send the result back via event
            mainHandler.post(() -> {
                // Simulate launching payment flow
                // In production: launch Google Pay / payment SDK activity
                try {
                    JSONObject result = new JSONObject();
                    result.put("paymentSessionId", paymentSessionId);
                    result.put("orderId", orderId);
                    result.put("status", "payment_ui_launched");
                    sendToWeb("paymentResult", result);
                } catch (JSONException e) {
                    Log.e(TAG, "Error sending payment result", e);
                }
            });

            JSONObject response = new JSONObject();
            response.put("status", "success");
            JSONObject data = new JSONObject();
            data.put("paymentSessionId", paymentSessionId);
            data.put("message", "Payment flow initiated. Listen for 'paymentResult' event.");
            response.put("data", data);
            return response.toString();
        } catch (JSONException e) {
            return createErrorResponse("ERROR", "Failed to initiate payment");
        }
    }

