    // --- Utility Methods ---

    private String createErrorResponse(String code, String message) {
        try {
            JSONObject response = new JSONObject();
            response.put("status", "error");
            JSONObject error = new JSONObject();
            error.put("code", code);
            error.put("message", message);
            response.put("error", error);
            return response.toString();
        } catch (JSONException e) {
            return "{\"status\":\"error\",\"error\":{\"code\":\"INTERNAL\",\"message\":\"Internal error\"}}";
        }
    }

    private String getAppVersionName() {
        try {
            return getPackageManager()
                    .getPackageInfo(getPackageName(), 0).versionName;
        } catch (PackageManager.NameNotFoundException e) {
            return "unknown";
        }
    }

    private long getAppVersionCode() {
        try {
            return getPackageManager()
                    .getPackageInfo(getPackageName(), 0).getLongVersionCode();
        } catch (PackageManager.NameNotFoundException e) {
            return -1;
        }
    }

    // --- Permission Results ---

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);

        boolean granted = grantResults.length > 0
                && grantResults[0] == PackageManager.PERMISSION_GRANTED;

        switch (requestCode) {
            case PERMISSION_REQUEST_CAMERA:
                try {
                    JSONObject result = new JSONObject();
                    result.put("granted", granted);
                    sendToWeb("cameraPermissionResult", result);
                } catch (JSONException e) {
                    Log.e(TAG, "Error sending camera permission result", e);
                }
                break;

            case PERMISSION_REQUEST_LOCATION:
                try {
                    JSONObject result = new JSONObject();
                    result.put("granted", granted);
                    if (granted) {
                        result.put("message", "Permission granted. Call requestLocation again to get coordinates.");
                    }
                    sendToWeb("locationPermissionResult", result);
                } catch (JSONException e) {
                    Log.e(TAG, "Error sending location permission result", e);
                }
                break;
        }
    }

    // --- Lifecycle ---

    @Override
    public void onBackPressed() {
        if (webView != null && webView.canGoBack()) {
            // Only go back within allowed origins
            webView.goBack();
        } else {
            super.onBackPressed();
        }
    }

    @Override
    protected void onPause() {
        super.onPause();
        if (webView != null) {
            webView.onPause();
        }
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (webView != null) {
            webView.onResume();
        }
    }

    @Override
    protected void onDestroy() {
        if (webView != null) {
            webView.removeJavascriptInterface("NativeBridge");
            webView.stopLoading();
            webView.destroy();
            webView = null;
        }
        usedNonces.clear();
        rateLimitMap.clear();
        super.onDestroy();
    }
